import os
from flask import Flask, request, jsonify
import pymysql

app = Flask(__name__)

def connect_to_db():
    config = {
        'host': os.environ['DB_HOST'],
        'user': os.environ['DB_USER'],
        'password': os.environ['DB_PASSWORD'],
        'database': os.environ['DB_NAME']
    }
    return pymysql.connect(**config)

@app.route('/search', methods=['GET'])
def search():
    db = connect_to_db()
    cursor = db.cursor()

    query = "SELECT * FROM your_table WHERE "

    for key, value in request.args.items():
        if key not in ('page', 'limit'):  # Assuming page and limit are pagination parameters
            query += f"{key} = '{value}' AND "

    query = query[:-4]  # Remove the last AND

    cursor.execute(query)
    result = cursor.fetchall()

    db.close()

    data = []
    for row in result:
        data.append({column[0]: row[column[0]] for column in cursor.description})

    return jsonify(data)

if __name__ == '__main__':
    app.run(debug=True, host='127.0.0.1', port=8080)